#include <bits/stdc++.h>
using namespace std;
int main() {
    string s;
    if (!(cin >> s)) return 0;
    int balance = 0;
    for (char c : s) {
        balance += c == '(' ? 1 : -1;
        if (balance < 0) {
            cout << "NO\n";
            return 0;
        }
    }
    cout << (balance == 0 ? "YES" : "NO") << '\n';
}
